            )

for uri, item in self.source_map.items():
            if item["type"] == source_type:
                if is_numeric_search:
                    num = item.get("dispNum")
                    if num and int(query) == int(num):
                        return await self.async_source_start(uri, source_type)
                else:
                    title: str = item["title"]
                    if query.lower() == title.lower():
                        return await self.async_source_start(uri, source_type)
                    if query.lower() in title.lower():
                        coarse_uri = uri

if media_content_type == MediaType.TRACK:
            result = await self.api.get_track(int(item_id_str))
        elif media_content_type == MediaType.ALBUM:
            if result := await self.api.get_albums():
                result = next(
                    (item for item in result if item["id"] == item_id_str), None
                )
        elif result := await self.api.get_artists():
            result = next((item for item in result if item["id"] == item_id_str), None)

for entry in service.hass.config_entries.async_loaded_entries(DOMAIN):
        if entity_id_list != "all":
            for entity_id in entity_id_list:
                device = entry.runtime_data.hmip_device_by_entity_id.get(entity_id)
                if device and isinstance(device, SwitchMeasuring):
                    await device.reset_energy_counter_async()
        else:
            for device in entry.runtime_data.home.devices:
                if isinstance(device, SwitchMeasuring):
                    await device.reset_energy_counter_async()

if zone_current_mode == OPERATION_MODE_HEAT:
            if self._thermostat.has_humidify_support():
                await self.async_set_humidify_setpoint(humidity)
        elif zone_current_mode == OPERATION_MODE_COOL:
            if self._thermostat.has_dehumidify_support():
                await self.async_set_dehumidify_setpoint(humidity)
        else:
            if self._thermostat.has_humidify_support():
                await self.async_set_humidify_setpoint(humidity)
            if self._thermostat.has_dehumidify_support():
                await self.async_set_dehumidify_setpoint(humidity)

if user_input is not None:
            try:
                info = await validate_input(self.hass, user_input)
            except CannotConnect:
                errors["base"] = "cannot_connect"
            except InvalidAuth:
                errors["base"] = "invalid_auth"
            except Exception:
                _LOGGER.exception("Unexpected exception")
                errors["base"] = "unknown"

            if "base" not in errors:
                await self.async_set_unique_id(str(info["house_id"]))
                self._abort_if_unique_id_configured()
                return self.async_create_entry(title=info["title"], data=user_input)

